import { Component, inject, ViewEncapsulation } from '@angular/core';
import { Router } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { from } from 'rxjs'; // 🚀 Importation requise pour encapsuler la promesse fetch

@Component({
  selector: 'app-job-create',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './job-create.component.html',
  styleUrls: ['./job-create.component.css'],
  encapsulation: ViewEncapsulation.None 
})
export class JobCreateComponent {
  private router = inject(Router);

  // Données synchronisées avec le HTML
  job = { 
    title: '', 
    contract_type: 'CDI', 
    location: '', 
    workplace_type: 'Présentiel', 
    salary: '', 
    experience_level: 'Junior (0-2 ans)', 
    missions_desc: '', 
    profile_desc: '', 
    expires_at: '' 
  };

  onPublish(event: Event) {
    event.preventDefault(); // Coupe le rechargement de page

    // Validation locale obligatoire
    if (!this.job.title || !this.job.location || !this.job.missions_desc || !this.job.profile_desc) {
      alert("Veuillez renseigner l'intégralité des champs obligatoires marqués d'un astérisque (*).");
      return;
    }

    console.log("Transmission directe au serveur :", this.job);

    // 🚀 ALIGNEMENT FORCE ET ETANCHE SUR L'IP LOCAL ET LE PORT 3000 DU BACKEND
    const targetUrl = 'http://127.0.0';
    const token = localStorage.getItem('token');

    // Génération de la promesse fetch native
    const promise = fetch(targetUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': token ? `Bearer ${token}` : '' // Transmet le Token JWT requis par verifyToken
      },
      body: JSON.stringify(this.job)
    }).then(async res => {
      if (!res.ok) {
        const errorBody = await res.json().catch(() => ({}));
        throw new Error(errorBody.message || "Erreur serveur.");
      }
      return res.json();
    });

    // Conversion en Observable pour conserver votre structure de souscription
    from(promise).subscribe({
      next: (res: any) => {
        alert(res.message || "Annonce d'emploi diffusée avec succès sur TunJob Portal !");
        // Redirection pro vers votre liste
        this.router.navigate(['/recruiter/job-manage']); 
      },
      error: (err) => {
        console.error("Échec de l'insertion de l'annonce :", err);
        alert("Impossible de diffuser l'offre. Vérifiez que votre serveur backend (Port 3000) et votre base de données MySQL sont actifs.");
      }
    });
  }
}
